import { Link } from 'react-router-dom';

const values = [
  ['01', 'Compassion first', 'We listen carefully, respond with dignity, and make every person feel seen.'],
  ['02', 'Community powered', 'Local voices lead the way from the first conversation to lasting change.'],
  ['03', 'Transparent action', 'We share progress openly so every contribution has a clear purpose.']
];

export default function About() {
  return <>
    <section className="about-hero"><div className="container"><span className="eyebrow">Our purpose</span><h1>Small acts of care.<br />Lasting change.</h1><p>The Arise '20 Foundation brings people together to create practical, hopeful change across Salem.</p></div></section>
    <main>
      <section className="about-intro container"><div className="about-image-stack"><img src="https://images.unsplash.com/photo-1529156069898-49953e39b3ac?auto=format&fit=crop&w=1000&q=85" alt="Foundation volunteers together" /><div className="years-card"><strong>06</strong><span>years of<br />community care</span></div></div><div><span className="eyebrow">How it began</span><h2>A belief that kindness becomes stronger when shared.</h2><p>What started as a handful of friends responding to a local need has grown into a community of volunteers, donors, and partners who show up with consistency and heart.</p><p>We connect immediate support with opportunity—serving meals today while building confidence, health, and hope for tomorrow.</p><Link to="/volunteer" className="btn btn-dark">Join our movement →</Link></div></section>
      <section className="about-purpose"><div className="container purpose-grid"><div><span className="eyebrow">What guides us</span><h2>Every person deserves the chance to rise.</h2></div><div className="purpose-cards"><article><span>⌁</span><h3>Our vision</h3><p>A compassionate, empowered community where no one is left behind.</p></article><article><span>↗</span><h3>Our mission</h3><p>Deliver practical support and community-led programs that restore dignity and hope.</p></article></div></div></section>
      <section className="values-section container"><div className="section-title"><span className="eyebrow">Our values</span><h2>Care is how we work.</h2></div><div className="value-list">{values.map(([number, title, text]) => <article key={number}><span>{number}</span><div><h3>{title}</h3><p>{text}</p></div></article>)}</div></section>
      <section className="about-impact"><div className="container"><div><span className="eyebrow">Impact in action</span><h2>Purpose you can see in every neighbourhood.</h2></div><div className="about-metrics"><div><strong>1,500+</strong><span>families supported</span></div><div><strong>3,000+</strong><span>meals served</span></div><div><strong>500+</strong><span>volunteers united</span></div></div></div></section>
      <section className="about-cta container"><div><span className="eyebrow">Make a difference</span><h2>There is a place for you in this story.</h2><p>Bring your time, talent, or contribution to the next act of care.</p></div><div><Link className="btn btn-primary" to="/donate">Donate now</Link><Link className="btn btn-secondary" to="/volunteer">Volunteer with us</Link></div></section>
    </main>
  </>;
}
